final class AppSettings: ObservableObject {
    static let shared = AppSettings()
    static let notificationName = NSNotification.Name("UnrestrictedModeChanged")

    @Published var unrestrictedTools: Bool = false {
        didSet {
            UserDefaults.standard.set(unrestrictedTools, forKey: Keys.unrestrictedTools)
            if unrestrictedTools { privateMode = false }
            objectWillChange.send()
            NotificationCenter.default.post(name: Self.notificationName, object: nil)
        }
    }

    @Published var privateMode: Bool = false {
        didSet {
            if unrestrictedTools && privateMode { privateMode = false }
            UserDefaults.standard.set(privateMode, forKey: Keys.privateMode)
            objectWillChange.send()
        }
    }

    var isUnrestrictedActive: Bool { unrestrictedTools }

    private init() {
        unrestrictedTools = UserDefaults.standard.bool(forKey: Keys.unrestrictedTools)
        privateMode = UserDefaults.standard.bool(forKey: Keys.privateMode)
        if unrestrictedTools { privateMode = false }
    }

    private enum Keys {
        static let unrestrictedTools = "unrestrictedTools"
        static let privateMode = "privateMode"
    }

    static func enableUnrestrictedMode() { shared.unrestrictedTools = true }
    static func disableUnrestrictedMode() { shared.unrestrictedTools = false }
}
