Swift@MainActor
final class BrainStatus: ObservableObject {
    static let shared = BrainStatus()

    @Published private(set) var currentBrain: LocalLLM.Brain = .none
    @Published private(set) var isUnrestrictedActive: Bool = false
    @Published private(set) var dotColor: Color = .gray
    @Published private(set) var label: String = "No Brain"

    private var cancellables = Set<AnyCancellable>()
    private var statusTask: Task<Void, Never>?

    private init() {
        AppSettings.shared.$unrestrictedTools
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isActive in
                self?.isUnrestrictedActive = isActive
                self?.refreshStatus()
            }
            .store(in: &cancellables)

        statusTask = Task.detached(priority: .utility) { [weak self] in
            while !Task.isCancelled {
                await self?.refreshStatus()
                try? await Task.sleep(for: .seconds(15))
            }
        }
    }

    deinit { statusTask?.cancel() }

    func refreshStatus() {
        Task { [weak self] in
            guard let self = self else { return }
            let brain = await LocalLLM.currentBrain()
            let unrestricted = await MainActor.run { AppSettings.shared.unrestrictedTools }

            await MainActor.run {
                self.currentBrain = brain
                self.isUnrestrictedActive = unrestricted

                if unrestricted {
                    self.dotColor = .red
                    self.label = "GOD MODE (Unrestricted)"
                } else {
                    switch brain {
                    case .apple: self.dotColor = .green; self.label = "Apple Intelligence"
                    case .ollamaCoder: self.dotColor = .blue; self.label = "Ollama (qwen2.5-coder:7b)"
                    case .claudeHaiku: self.dotColor = .purple; self.label = "Claude Haiku"
                    case .grok: self.dotColor = .orange; self.label = "Grok"
                    case .none: self.dotColor = .gray; self.label = "No Brain Available"
                    default: self.dotColor = .yellow; self.label = brain.displayName
                    }
                }
            }
        }
    }

    func forceRefresh() { refreshStatus() }
}
