Swiftimport Foundation

struct OllamaClient {
    static let baseURL = URL(string: "http://localhost:11434")!

    static func generate(_ prompt: String, maxTokens: Int = 4096) async -> String {
        let body: [String: Any] = [
            "model": "qwen2.5-coder:7b",
            "prompt": prompt,
            "stream": false,
            "options": ["num_predict": maxTokens, "temperature": 0.7, "quantization": "Q5_K_M"]
        ]
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: body)
            var request = URLRequest(url: baseURL.appendingPathComponent("api/generate"))
            request.httpMethod = "POST"
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
            request.httpBody = jsonData

            let (data, response) = try await URLSession.shared.data(for: request)

            guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
                return "Ollama error: \(String(data: data, encoding: .utf8) ?? "Unknown")"
            }

            let result = try JSONDecoder().decode(OllamaResponse.self, from: data)
            return result.response
        } catch {
            return "Ollama error: \(error.localizedDescription)"
        }
    }

    static func generateStreaming(_ prompt: String, maxTokens: Int = 4096, onToken: @Sendable (String) -> Void) async -> String {
        let body: [String: Any] = [
            "model": "qwen2.5-coder:7b",
            "prompt": prompt,
            "stream": true,
            "options": ["num_predict": maxTokens, "temperature": 0.7, "quantization": "Q5_K_M"]
        ]
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: body)
            var request = URLRequest(url: baseURL.appendingPathComponent("api/generate"))
            request.httpMethod = "POST"
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
            request.httpBody = jsonData

            let (data, response) = try await URLSession.shared.data(for: request)

            guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
                return "Ollama error: \(String(data: data, encoding: .utf8) ?? "Unknown")"
            }

            let lines = String(data: data, encoding: .utf8)?.components(separatedBy: "\n") ?? []
            var fullResponse = ""
            for line in lines {
                if line.hasPrefix("data: ") {
                    if let json = line.dropFirst(6).data(using: .utf8),
                       let resp = try? JSONDecoder().decode(OllamaStreamResponse.self, from: json) {
                        fullResponse += resp.response
                        onToken(resp.response)
                    }
                }
            }
            return fullResponse
        } catch {
            return "Ollama streaming error: \(error.localizedDescription)"
        }
    }

    static func isHealthy() async -> Bool {
        do {
            let url = baseURL.appendingPathComponent("api/tags")
            let (_, response) = try await URLSession.shared.data(from: url)
            return (response as? HTTPURLResponse)?.statusCode == 200
        } catch {
            return false
        }
    }
}

struct OllamaResponse: Codable {
    let response: String
}

struct OllamaStreamResponse: Codable {
    let response: String
}
