Swift@MainActor
final class KnowledgeStore: ObservableObject {
    static let shared = KnowledgeStore()

    private var db: OpaquePointer?
    private let dbPath = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
        .appendingPathComponent("knowledge.db").path

    @Published var documents: [KnowledgeDocument] = []

    private init() {
        openDatabase()
        createTable()
        loadDocuments()
    }

    private func openDatabase() {
        if sqlite3_open(dbPath, &db) != SQLITE_OK { print("Failed to open database") }
        sqlite3_exec(db, "PRAGMA journal_mode=WAL;", nil, nil, nil)
        sqlite3_exec(db, "PRAGMA cache_size=10000;", nil, nil, nil)
    }

    private func createTable() {
        let createSQL = """
        CREATE TABLE IF NOT EXISTS documents (
            id TEXT PRIMARY KEY,
            title TEXT,
            content TEXT,
            embedding BLOB,
            timestamp INTEGER
        );
        CREATE INDEX IF NOT EXISTS idx_timestamp ON documents(timestamp);
        """
        var statement: OpaquePointer?
        sqlite3_prepare_v2(db, createSQL, -1, &statement, nil)
        sqlite3_step(statement)
        sqlite3_finalize(statement)
    }

    func search(_ query: String, limit: Int = 5) async -> [KnowledgeDocument] {
        let queryEmbedding = await getEmbedding(query)
        var results: [(doc: KnowledgeDocument, similarity: Float)] = []

        let sql = "SELECT id, title, content, embedding FROM documents ORDER BY timestamp DESC"
        var statement: OpaquePointer?
        sqlite3_prepare_v2(db, sql, -1, &statement, nil)

        while sqlite3_step(statement) == SQLITE_ROW {
            let id = String(cString: sqlite3_column_text(statement, 0))
            let title = String(cString: sqlite3_column_text(statement, 1))
            let content = String(cString: sqlite3_column_text(statement, 2))
            let embeddingData = sqlite3_column_blob(statement, 3)
            let length = sqlite3_column_bytes(statement, 3)

            guard let data = Data(bytes: embeddingData, count: Int(length)),
                  let stored = try? JSONDecoder().decode([Float].self, from: data) else { continue }

            let similarity = cosineSimilarity(queryEmbedding, stored)
            if similarity > 0.75 {
                results.append((KnowledgeDocument(id: id, title: title, content: content), similarity))
            }
        }
        sqlite3_finalize(statement)

        return results.sorted { $0.similarity > $1.similarity }.prefix(limit).map { $0.doc }
    }

    func addDocuments(_ docs: [KnowledgeDocument]) async {
        sqlite3_exec(db, "BEGIN TRANSACTION;", nil, nil, nil)

        let insertSQL = "INSERT OR REPLACE INTO documents (id, title, content, embedding, timestamp) VALUES (?, ?, ?, ?, ?)"
        var statement: OpaquePointer?
        sqlite3_prepare_v2(db, insertSQL, -1, &statement, nil)

        for doc in docs {
            let embedding = await getEmbedding(doc.content)
            sqlite3_bind_text(statement, 1, doc.id, -1, nil)
            sqlite3_bind_text(statement, 2, doc.title, -1, nil)
            sqlite3_bind_text(statement, 3, doc.content, -1, nil)
            sqlite3_bind_blob(statement, 4, try? JSONEncoder().encode(embedding), Int32(embedding.count * MemoryLayout<Float>.size), nil)
            sqlite3_bind_int64(statement, 5, Int64(Date().timeIntervalSince1970))
            sqlite3_step(statement)
            sqlite3_reset(statement)
        }
        sqlite3_finalize(statement)
        sqlite3_exec(db, "COMMIT;", nil, nil, nil)

        loadDocuments()
    }

    private func getEmbedding(_ text: String) async -> [Float] {
        if let model = try? MLModel(contentsOf: URL(fileURLWithPath: "CoreML/embedding.mlmodelc")) {
            let input = try? MLFeatureValue(dictionary: ["text": text])
            let output = try? model.prediction(from: input!)
            return output?["embedding"].arrayValue as? [Float] ?? []
        }
        return await OllamaClient.getEmbedding(text) ?? []
    }

    private func cosineSimilarity(_ a: [Float], _ b: [Float]) -> Float {
        var dot: Float = 0, normA: Float = 0, normB: Float = 0
        let minCount = min(a.count, b.count)
        for i in 0..<minCount {
            dot += a[i] * b[i]
            normA += a[i] * a[i]
            normB += b[i] * b[i]
        }
        return dot / (sqrt(normA) * sqrt(normB))
    }

    private func loadDocuments() {
        documents = [] // Reload logic
    }
}

struct KnowledgeDocument: Identifiable, Codable {
    let id: String
    let title: String
    let content: String
}

