/// Named tuning thresholds for the multi-agent pipeline.
/// Exposed publicly so they are discoverable and tunable in one place
/// (token budgets, trivial-mission heuristics, etc.).
public enum AgentThresholds {
    public static let maxTurnLength = 4_000
    public static let turnHistorySize = 8
    public static let fullTokens = 700
    public static let shortTokens = 110
    public static let trivialLength = 40
    public static let longMessageLength = 200
    public static let wordCountThreshold = 30
    public static let rawPromptTokens = 300
    public static let greetingWords = 8   // increased for safety; protects short real questions
}

nonisolated static func isTrivialMission(_ mission: String) -> Bool {
    let trimmed = mission.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty, !trimmed.contains("\n"), trimmed.count <= AgentThresholds.trivialLength else { return false }
    if trimmed.contains("?") { return false }

    let normalized = trimmed.lowercased()
        .trimmingCharacters(in: CharacterSet(charactersIn: ".!,…"))

    // Arabic + English greetings (Riyadh user + international)
    let greetings: Set<String> = [
        "hi", "hello", "hey", "yo", "sup", "hiya", "gm", "good morning",
        "good evening", "good afternoon", "good night", "salam", "salaam",
        "hola", "thanks", "thank you", "thx", "ty", "ok", "okay", "k",
        "cool", "nice", "great", "good", "got it", "gotcha", "perfect",
        "awesome", "test", "ping", "hello there", "how are you",
        "how's it going", "whats up", "what's up", "wassup",
        "marhaba", "ahlan", "salaam alaikum", "wa alaikum assalam"
    ]
    if greetings.contains(normalized) { return true }

    let words = normalized.split(separator: " ")
    guard words.count <= AgentThresholds.greetingWords else { return false }
    if normalized.contains(where: { $0.isNumber }) { return false }
    // Expanded shell/code chars so short commands ("ls -la", "git status", "brew install") are NOT trivial
    if normalized.contains(where: { "{}()[]<>/\\=;`|-&>!#".contains($0) }) { return false }
    return true
}

nonisolated static func complexity(of mission: String) -> MissionComplexity {
    let trimmed = mission.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return .simple }
    let lower = trimmed.lowercased()
    let wordCount = trimmed.split { $0 == " " || $0 == "\n" }.count

    let hardPhrases = [ /* existing list unchanged */ ]
    let hasHardPhrase = hardPhrases.contains { lower.contains($0) }
    let multiLine = trimmed.contains("\n")
    let looksLikeCode = trimmed.contains("```") || trimmed.contains("{") || trimmed.contains(";")
    let long = trimmed.count > AgentThresholds.longMessageLength || wordCount > AgentThresholds.wordCountThreshold
    let multiSentence = trimmed.filter { ".!?".contains($0) }.count >= 2
    if hasHardPhrase || multiLine || looksLikeCode || long || multiSentence {
        return .hard
    }

    if isTrivialMission(mission) { return .simple }
    if wordCount <= AgentThresholds.greetingWords { return .simple }

    return .moderate
}
