    /// Reusable icon-only button that guarantees DS tokens, .accessibilityLabel, and VoiceOver compliance.
    /// Every icon-only Button/Menu in the app must use this (or an equivalent with explicit .accessibilityLabel).
    struct IconButton<Label: View>: View {
        let action: () -> Void
        let accessibilityLabel: String
        @ViewBuilder let label: () -> Label

        var body: some View {
            Button(action: action) {
                label()
                    .foregroundStyle(DS.Palette.accent)
                    .frame(width: 28, height: 28)
            }
            .buttonStyle(.plain)
            .accessibilityLabel(accessibilityLabel)
            .help(accessibilityLabel)
        }

        init(icon: String, accessibilityLabel: String, action: @escaping () -> Void) {
            self.action = action
            self.accessibilityLabel = accessibilityLabel
            self.label = { Image(systemName: icon) }
        }
    }
